package travelcare_agent.evaluation.dto; import travelcare_agent.evaluation.entity.EvaluationRun; public record EvaluationRunResponse(Long id,Long datasetId,Integer datasetVersion,String providerMode,String promptStubVersion,String status,Integer totalCount,Integer passedCount,Integer failedCount,Integer errorCount,Integer skippedCount,String summaryJson){public static EvaluationRunResponse from(EvaluationRun v){return new EvaluationRunResponse(v.getId(),v.getDatasetId(),v.getDatasetVersion(),v.getProviderMode(),v.getPromptStubVersion(),v.getStatus(),v.getTotalCount(),v.getPassedCount(),v.getFailedCount(),v.getErrorCount(),v.getSkippedCount(),v.getSummaryJson());}}
